#!/usr/bin/env python3
"""
Kafka Cluster Administration Script

Uses kafka-python AdminClient to create topics, manage partitions,
and configure topic settings via command-line arguments.
"""

import argparse
import sys
import json
import time
from kafka.admin import (
    KafkaAdminClient,
    NewTopic,
    NewPartitions,
    ConfigResource,
    ConfigResourceType,
)
from kafka.errors import (
    TopicAlreadyExistsError,
    UnknownTopicOrPartitionError,
    KafkaError,
)
from kafka import KafkaConsumer


def get_admin_client(bootstrap_servers, security_protocol="PLAINTEXT",
                     sasl_mechanism=None, sasl_plain_username=None,
                     sasl_plain_password=None):
    """Create and return a KafkaAdminClient instance."""
    config = {
        "bootstrap_servers": bootstrap_servers,
        "security_protocol": security_protocol,
        "client_id": "kafka-admin-tool",
    }

    if sasl_mechanism:
        config["sasl_mechanism"] = sasl_mechanism
    if sasl_plain_username:
        config["sasl_plain_username"] = sasl_plain_username
    if sasl_plain_password:
        config["sasl_plain_password"] = sasl_plain_password

    try:
        admin_client = KafkaAdminClient(**config)
        print(f"[OK] Connected to Kafka cluster at {bootstrap_servers}")
        return admin_client
    except KafkaError as e:
        print(f"[ERROR] Failed to connect to Kafka cluster: {e}")
        sys.exit(1)


def create_topics(admin_client, topics_config):
    """
    Create one or more topics.

    topics_config: list of dicts with keys:
        - name: topic name
        - num_partitions: number of partitions
        - replication_factor: replication factor
        - config: dict of topic-level configs (optional)
    """
    new_topics = []
    for topic in topics_config:
        topic_config = topic.get("config", {})
        new_topic = NewTopic(
            name=topic["name"],
            num_partitions=topic.get("num_partitions", 1),
            replication_factor=topic.get("replication_factor", 1),
            topic_configs=topic_config,
        )
        new_topics.append(new_topic)
        print(f"[INFO] Preparing to create topic '{topic['name']}' "
              f"(partitions={new_topic.num_partitions}, "
              f"replication_factor={new_topic.replication_factor}, "
              f"config={topic_config})")

    try:
        result = admin_client.create_topics(new_topics=new_topics, validate_only=False)
        print(f"[OK] Topics created successfully: {[t.name for t in new_topics]}")
        return result
    except TopicAlreadyExistsError as e:
        print(f"[WARN] One or more topics already exist: {e}")
    except KafkaError as e:
        print(f"[ERROR] Failed to create topics: {e}")
        sys.exit(1)


def delete_topics(admin_client, topic_names):
    """Delete one or more topics."""
    try:
        result = admin_client.delete_topics(topic_names)
        print(f"[OK] Topics deleted successfully: {topic_names}")
        return result
    except UnknownTopicOrPartitionError as e:
        print(f"[WARN] One or more topics not found: {e}")
    except KafkaError as e:
        print(f"[ERROR] Failed to delete topics: {e}")
        sys.exit(1)


def list_topics(admin_client):
    """List all topics in the cluster."""
    try:
        # Use a consumer to list topics as AdminClient doesn't have a direct method
        consumer = KafkaConsumer(
            bootstrap_servers=admin_client.config.get("bootstrap_servers", "localhost:9092"),
            security_protocol=admin_client.config.get("security_protocol", "PLAINTEXT"),
        )
        topics = consumer.topics()
        consumer.close()

        if topics:
            print(f"\n[INFO] Found {len(topics)} topics:")
            print("-" * 60)
            for topic in sorted(topics):
                print(f"  - {topic}")
            print("-" * 60)
        else:
            print("[INFO] No topics found in the cluster.")
        return topics
    except KafkaError as e:
        print(f"[ERROR] Failed to list topics: {e}")
        sys.exit(1)


def describe_topics(admin_client, topic_names):
    """Describe one or more topics including partition details."""
    try:
        topic_metadata = admin_client.describe_topics(topic_names)

        for topic_info in topic_metadata:
            topic_name = topic_info.get("topic", "unknown")
            partitions = topic_info.get("partitions", [])

            print(f"\n{'=' * 60}")
            print(f"Topic: {topic_name}")
            print(f"{'=' * 60}")
            print(f"  Number of Partitions: {len(partitions)}")

            for partition in partitions:
                partition_id = partition.get("partition", "N/A")
                leader = partition.get("leader", "N/A")
                replicas = partition.get("replicas", [])
                isr = partition.get("isr", [])
                print(f"\n  Partition {partition_id}:")
                print(f"    Leader: {leader}")
                print(f"    Replicas: {replicas}")
                print(f"    ISR: {isr}")

        return topic_metadata
    except UnknownTopicOrPartitionError as e:
        print(f"[WARN] Topic not found: {e}")
    except KafkaError as e:
        print(f"[ERROR] Failed to describe topics: {e}")
        sys.exit(1)


def add_partitions(admin_client, topic_partitions):
    """
    Increase the number of partitions for topics.

    topic_partitions: dict mapping topic name to new total partition count
    """
    new_partitions = {}
    for topic_name, total_count in topic_partitions.items():
        new_partitions[topic_name] = NewPartitions(total_count=total_count)
        print(f"[INFO] Setting partition count for '{topic_name}' to {total_count}")

    try:
        result = admin_client.create_partitions(new_partitions)
        print(f"[OK] Partitions updated successfully for topics: {list(topic_partitions.keys())}")
        return result
    except KafkaError as e:
        print(f"[ERROR] Failed to add partitions: {e}")
        sys.exit(1)


def get_topic_config(admin_client, topic_names):
    """Get configuration for one or more topics."""
    config_resources = [
        ConfigResource(ConfigResourceType.TOPIC, topic_name)
        for topic_name in topic_names
    ]

    try:
        result = admin_client.describe_configs(config_resources)

        for resource, future in result.items():
            print(f"\n{'=' * 60}")
            print(f"Configuration for topic: {resource.name}")
            print(f"{'=' * 60}")

            configs = future.result() if hasattr(future, 'result') else future
            if isinstance(configs, dict):
                for config_key, config_entry in sorted(configs.items()):
                    value = config_entry.value if hasattr(config_entry, 'value') else config_entry
                    is_default = config_entry.is_default if hasattr(config_entry, 'is_default') else 'N/A'
                    print(f"  {config_key} = {value} (default: {is_default})")
            else:
                print(f"  Config data: {configs}")

        return result
    except KafkaError as e:
        print(f"[ERROR] Failed to get topic configuration: {e}")
        sys.exit(1)


def alter_topic_config(admin_client, topic_name, config_dict):
    """
    Alter topic configuration.

    config_dict: dict of configuration key-value pairs to set
    """
    config_resource = ConfigResource(
        ConfigResourceType.TOPIC,
        topic_name,
        configs=config_dict,
    )

    try:
        result = admin_client.alter_configs([config_resource])
        print(f"[OK] Configuration updated for topic '{topic_name}': {config_dict}")
        return result
    except KafkaError as e:
        print(f"[ERROR] Failed to alter topic configuration: {e}")
        sys.exit(1)


def describe_cluster(admin_client):
    """Describe the Kafka cluster."""
    try:
        cluster_metadata = admin_client.describe_cluster()

        print(f"\n{'=' * 60}")
        print("Cluster Information")
        print(f"{'=' * 60}")

        if isinstance(cluster_metadata, dict):
            cluster_id = cluster_metadata.get("cluster_id", "N/A")
            controller = cluster_metadata.get("controller", "N/A")
            brokers = cluster_metadata.get("brokers", [])

            print(f"  Cluster ID: {cluster_id}")
            print(f"  Controller: {controller}")
            print(f"  Brokers ({len(brokers)}):")
            for broker in brokers:
                if isinstance(broker, dict):
                    print(f"    - ID: {broker.get('node_id', 'N/A')}, "
                          f"Host: {broker.get('host', 'N/A')}:"
                          f"{broker.get('port', 'N/A')}")
                else:
                    print(f"    - {broker}")
        else:
            print(f"  Metadata: {cluster_metadata}")

        return cluster_metadata
    except KafkaError as e:
        print(f"[ERROR] Failed to describe cluster: {e}")
        sys.exit(1)


def parse_config_string(config_string):
    """Parse a configuration string in format 'key1=value1,key2=value2'."""
    config = {}
    if config_string:
        for pair in config_string.split(","):
            pair = pair.strip()
            if "=" in pair:
                key, value = pair.split("=", 1)
                config[key.strip()] = value.strip()
    return config


def parse_topic_config_json(json_string):
    """Parse a JSON string containing topic configurations."""
    try:
        return json.loads(json_string)
    except json.JSONDecodeError as e:
        print(f"[ERROR] Invalid JSON configuration: {e}")
        sys.exit(1)


def build_parser():
    """Build the argument parser."""
    parser = argparse.ArgumentParser(
        description="Kafka Cluster Administration Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Create a topic
  %(prog)s --bootstrap-servers localhost:9092 create-topic \\
      --topic my-topic --partitions 3 --replication-factor 1

  # Create a topic with configuration
  %(prog)s --bootstrap-servers localhost:9092 create-topic \\
      --topic my-topic --partitions 6 --replication-factor 3 \\
      --config "retention.ms=86400000,cleanup.policy=compact"

  # Create multiple topics from JSON
  %(prog)s --bootstrap-servers localhost:9092 create-topics-json \\
      --json '[{"name":"t1","num_partitions":3,"replication_factor":1,"config":{"retention.ms":"86400000"}}]'

  # List all topics
  %(prog)s --bootstrap-servers localhost:9092 list-topics

  # Describe a topic
  %(prog)s --bootstrap-servers localhost:9092 describe-topic --topic my-topic

  # Delete topics
  %(prog)s --bootstrap-servers localhost:9092 delete-topic --topics my-topic1 my-topic2

  # Add partitions
  %(prog)s --bootstrap-servers localhost:9092 add-partitions \\
      --topic my-topic --num-partitions 10

  # Get topic configuration
  %(prog)s --bootstrap-servers localhost:9092 get-config --topics my-topic

  # Alter topic configuration
  %(prog)s --bootstrap-servers localhost:9092 alter-config \\
      --topic my-topic --config "retention.ms=172800000,max.message.bytes=2097152"

  # Describe cluster
  %(prog)s --bootstrap-servers localhost:9092 describe-cluster
        """,
    )

    # Global arguments
    parser.add_argument(
        "--bootstrap-servers",
        required=True,
        help="Kafka bootstrap servers (comma-separated list, e.g., 'host1:9092,host2:9092')",
    )
    parser.add_argument(
        "--security-protocol",
        default="PLAINTEXT",
        choices=["PLAINTEXT", "SSL", "SASL_PLAINTEXT", "SASL_SSL"],
        help="Security protocol (default: PLAINTEXT)",
    )
    parser.add_argument(
        "--sasl-mechanism",
        default=None,
        help="SASL mechanism (e.g., PLAIN, SCRAM-SHA-256)",
    )
    parser.add_argument(
        "--sasl-username",
        default=None,
        help="SASL username",
    )
    parser.add_argument(
        "--sasl-password",
        default=None,
        help="SASL password",
    )

    subparsers = parser.add_subparsers(dest="command", help="Administration command")

    # Create topic
    create_parser = subparsers.add_parser("create-topic", help="Create a single topic")
    create_parser.add_argument("--topic", required=True, help="Topic name")
    create_parser.add_argument(
        "--partitions", type=int, default=1, help="Number of partitions (default: 1)"
    )
    create_parser.add_argument(
        "--replication-factor",
        type=int,
        default=1,
        help="Replication factor (default: 1)",
    )
    create_parser.add_argument(
        "--config",
        default=None,
        help="Topic configuration as key=value pairs, comma-separated "
             "(e.g., 'retention.ms=86400000,cleanup.policy=compact')",
    )

    # Create multiple topics from JSON
    create_json_parser = subparsers.add_parser(
        "create-topics-json", help="Create multiple topics from JSON configuration"
    )
    create_json_parser.add_argument(
        "--json",
        required=True,
        help='JSON array of topic configs, e.g., '
             '\'[{"name":"t1","num_partitions":3,"replication_factor":1,'
             '"config":{"retention.ms":"86400000"}}]\'',
    )
    create_json_parser.add_argument(
        "--file",
        default=None,
        help="Path to JSON file with topic configurations (overrides --json)",
    )

    # List topics
    subparsers.add_parser("list-topics", help="List all topics")

    # Describe topic
    describe_parser = subparsers.add_parser("describe-topic", help="Describe topic(s)")
    describe_parser.add_argument(
        "--topic", required=True, nargs="+", help="Topic name(s) to describe"
    )

    # Delete topics
    delete_parser = subparsers.add_parser("delete-topic", help="Delete topic(s)")
    delete_parser.add_argument(
        "--topics", required=True, nargs="+", help="Topic name(s) to delete"
    )

    # Add partitions
    partition_parser = subparsers.add_parser(
        "add-partitions", help="Increase number of partitions for a topic"
    )
    partition_parser.add_argument("--topic", required=True, help="Topic name")
    partition_parser.add_argument(
        "--num-partitions",
        type=int,
        required=True,
        help="New total number of partitions (must be greater than current count)",
    )

    # Get topic config
    get_config_parser = subparsers.add_parser(
        "get-config", help="Get topic configuration"
    )
    get_config_parser.add_argument(
        "--topics", required=True, nargs="+", help="Topic name(s)"
    )

    # Alter topic config
    alter_config_parser = subparsers.add_parser(
        "alter-config", help="Alter topic configuration"
    )
    alter_config_parser.add_argument("--topic", required=True, help="Topic name")
    alter_config_parser.add_argument(
        "--config",
        required=True,
        help="Configuration as key=value pairs, comma-separated "
             "(e.g., 'retention.ms=86400000,max.message.bytes=2097152')",
    )

    # Describe cluster
    subparsers.add_parser("describe-cluster", help="Describe the Kafka cluster")

    return parser


def main():
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    # Parse bootstrap servers
    bootstrap_servers = [s.strip() for s in args.bootstrap_servers.split(",")]

    # Create admin client
    admin_client = get_admin_client(
        bootstrap_servers=bootstrap_servers,
        security_protocol=args.security_protocol,
        sasl_mechanism=args.sasl_mechanism,
        sasl_plain_username=args.sasl_username,
        sasl_plain_password=args.sasl_password,
    )

    try:
        if args.command == "create-topic":
            topic_config = parse_config_string(args.config) if args.config else {}
            topics_config = [
                {
                    "name": args.topic,
                    "num_partitions": args.partitions,
                    "replication_factor": args.replication_factor,
                    "config": topic_config,
                }
            ]
            create_topics(admin_client, topics_config)

        elif args.command == "create-topics-json":
            if args.file:
                with open(args.file, "r") as f:
                    topics_config = json.load(f)
            else:
                topics_config = parse_topic_config_json(args.json)

            if not isinstance(topics_config, list):
                print("[ERROR] JSON must be an array of topic configurations")
                sys.exit(1)

            create_topics(admin_client, topics_config)

        elif args.command == "list-topics":
            list_topics(admin_client)

        elif args.command == "describe-topic":
            describe_topics(admin_client, args.topic)

        elif args.command == "delete-topic":
            # Confirmation prompt
            topics_str = ", ".join(args.topics)
            confirm = input(
                f"[WARN] Are you sure you want to delete topics: {topics_str}? (yes/no): "
            )
            if confirm.lower() in ("yes", "y"):
                delete_topics(admin_client, args.topics)
            else:
                print("[INFO] Deletion cancelled.")

        elif args.command == "add-partitions":
            topic_partitions = {args.topic: args.num_partitions}
            add_partitions(admin_client, topic_partitions)

        elif args.command == "get-config":
            get_topic_config(admin_client, args.topics)

        elif args.command == "alter-config":
            config_dict = parse_config_string(args.config)
            if not config_dict:
                print("[ERROR] No valid configuration provided.")
                sys.exit(1)
            alter_topic_config(admin_client, args.topic, config_dict)

        elif args.command == "describe-cluster":
            describe_cluster(admin_client)

        else:
            parser.print_help()

    finally:
        try:
            admin_client.close()
            print("\n[OK] Admin client connection closed.")
        except Exception:
            pass


if __name__ == "__main__":
    main()